targetCode.css:
body {
  min-height: 100vh;
  margin: 0;
  display: grid;
  place-items: center;
  background: #f2f5f0;
}

.gallery {
  width: min(900px, 92vw);
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
  gap: 16px;
}

.gallery article {
  min-height: 150px;
  display: grid;
  place-items: center;
  border-radius: 18px;
  background: #264653;
  color: #fffdf8;
  font-size: 1.25rem;
  font-weight: 800;
}
